import{_ as r,o as t,c as s,j as e,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"缚命红绳","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/4.A级/缚命红绳.md","filePath":"4.资源分区/7.物品与装备/4.奇物/4.A级/缚命红绳.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/4.A级/缚命红绳.md"};function p(l,a,_,i,b,c){return t(),s("div",null,[...a[0]||(a[0]=[e("h1",{id:"缚命红绳",tabindex:"-1"},[n("缚命红绳 "),e("a",{class:"header-anchor",href:"#缚命红绳","aria-label":'Permalink to "缚命红绳"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"灵魂蓝调013")])])],-1),o('<h1 id="缚命红绳-1" tabindex="-1">缚命红绳 <a class="header-anchor" href="#缚命红绳-1" aria-label="Permalink to &quot;缚命红绳&quot;">​</a></h1><p>缚命红绳</p><p>A+4000<br> 奇物<br> 占用饰品栏<br> 传说中月老牵红线，造就不少神仙伴侣羡煞旁人。这红绳……也许是我和她的契机。<br> 【千里姻缘】你必须拥有一个强烈执念的目标，不管你对他/她的感情是什么，必须有强烈执念。在你持有这红绳的时候，只要在你的敏感范围内，你可以清晰的感知到你的执念目标，这视为一个C级的特异本质侦查，并附带灵视。<br> 强烈执念的判定标准为：若是喜欢，则愿意为她/他付出一切（包括生命），若是仇恨，在危险的情况也要击杀对方，或者拉对方同归于尽……（各种感情由扮演而定，若无法扮演则无法触发该效果也不会触发【缚命】特性。）<br> 我……我终于找到你了。</p><p>【缚命】我们系上这红绳，我们便是一个人，我们同生共死……<br> 你可以给目标在自愿或者在你将对方打到迷情或者支配的（需要将对方打入异常毁灭状态）情况下，帮其系上红绳，此后你们的命运便绑在一起了。<br> 同生共死：你们视为一个人，一人受到伤害，另一人也会收到一样的伤害，若一方在此状态下死亡，死亡方将化为亡魂，不管多远都会追上另一方，对其进行一次伤害，该次伤害视为一次常驻攻击，该次伤害为精神伤害，不论怎么样，只要造成1点伤害，则会肝胆俱裂而死，这视为S级命运来源即死。<br> 视觉表现为对方被打了一拳，你的身躯上莫名其妙出现了淤青，并且你也感到了疼痛……<br> ps：对方高X，你也会高X<br> 用同生共死之誓，换你我永不超生！</p><p>【情丝易断】红绳被系上后便消失在别人眼中，这条红绳只有双方才能看的见。若想解掉红绳，没有获得另一方的同意，则无法解脱。<br> 但红绳能被望气术或者任意相关命运类侦测所发现，发现者可以用一把普通的剪刀剪断红绳。 红绳被解或者剪后，都会立即消散。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
